# TODO make imro example parameterize
class ImroIOTest(unittest.TestCase):

    def assert_channelmap_equals(self, a, b):
        self.assertIsInstance(a, ChannelMap)
        self.assertIsInstance(b, ChannelMap)
        self.assertEqual(a.probe_type.code, b.probe_type.code, 'probe type mismatched')
        self.assertEqual(a.reference, b.reference, 'reference mismatched')
        self.assertEqual(len(a), len(b), 'channel count mismatched')
        for i, e, t in zip(range(a.n_channels), a.channels, b.channels):
            self.assertEqual(e, t, f'channel mismatch at {i}')

    def test_str_imro(self):
        chmap = io.parse_imro(IMRO_NP24)
        self.assertIsInstance(chmap, ChannelMap)
        self.assertEqual(IMRO_NP24, io.string_imro(chmap))

