    def test_probe_interface(self):
        chmap = io.parse_imro(IMRO_NP24)
        probe = io.to_probe(chmap)
        new_chmap = io.from_probe(probe)
        self.assert_channelmap_equals(chmap, new_chmap)

    def test_to_pandas(self):
        chmap = io.parse_imro(IMRO_NP24)
        df = io.to_pandas(chmap)
        cr = io.to_numpy(chmap, 'cr')
        sxy = io.to_numpy(chmap, 'sxy')
        assert_array_equal(sxy[:, 0], df['shank'].to_numpy())
        assert_array_equal(sxy[:, 1], df['x'].to_numpy())
        assert_array_equal(sxy[:, 2], df['y'].to_numpy())
        assert_array_equal(cr[:, 1], df['column'].to_numpy())
        assert_array_equal(cr[:, 2], df['row'].to_numpy())

    def test_to_polars(self):
        chmap = io.parse_imro(IMRO_NP24)
        df = io.to_polars(chmap)
        cr = io.to_numpy(chmap, 'cr')
        sxy = io.to_numpy(chmap, 'sxy')
        assert_array_equal(sxy[:, 0], df['shank'].to_numpy())
        assert_array_equal(sxy[:, 1], df['x'].to_numpy())
        assert_array_equal(sxy[:, 2], df['y'].to_numpy())
        assert_array_equal(cr[:, 1], df['column'].to_numpy())
        assert_array_equal(cr[:, 2], df['row'].to_numpy())


